previewCss:
.darma-loader-uiverse-redirect-progress-card {
  width: 240px;
  height: 130px;
  border-radius: 10px;
  background: #fff;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: space-evenly;
  padding: 30px;
  box-shadow: 2px 2px 10px -5px lightgrey;
}
.darma-loader-uiverse-redirect-progress-card__loading {
  width: 100%;
  height: 10px;
  background: lightgrey;
  border-radius: 10px;
  position: relative;
}
.darma-loader-uiverse-redirect-progress-card__loading::after {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  width: 50%;
  height: 10px;
  background: #002;
  border-radius: 10px;
  z-index: 1;
  animation: darma-loader-uiverse-redirect-progress-card-loading 0.6s alternate infinite;
}
.darma-loader-uiverse-redirect-progress-card label {
  color: #002;
  font-size: 18px;
  animation: darma-loader-uiverse-redirect-progress-card-bit 0.6s alternate infinite;
}

@keyframes darma-loader-uiverse-redirect-progress-card-bit {
from {
opacity: 0.3;
}
to {
opacity: 1;
}
}

@keyframes darma-loader-uiverse-redirect-progress-card-loading {
0% {
left: 25%;
}
100% {
left: 50%;
}
0% {
left: 0%;
}
}

